import{_ as r,o as t,c as a,ah as s}from"./chunks/framework.Be4cSgRn.js";const g=JSON.parse('{"title":"Fase 1: Netværksarkitektur & backbone","description":"","frontmatter":{"title":"Fase 1: Netværksarkitektur & backbone","phase":1,"topic":"infrastruktur","personas":["arkitekt","driftsleder"],"tags":["netværk","spine-leaf","QoS","IPAM","multi-tenancy"],"priority":"kritisk-sti","dependencies":[]},"headers":[],"relativePath":"faser/01-netvaerk.md","filePath":"faser/01-netvaerk.md"}'),i={name:"faser/01-netvaerk.md"};function n(l,e,o,k,p,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="fase-1-netværksarkitektur-backbone" tabindex="-1">Fase 1: Netværksarkitektur &amp; backbone <a class="header-anchor" href="#fase-1-netværksarkitektur-backbone" aria-label="Permalink to &quot;Fase 1: Netværksarkitektur &amp; backbone&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="critical-path-badge">Kritisk sti</span></span><span><strong>Afhænger af:</strong> Ingen (startpunkt)</span><span><strong>Blokerer:</strong> Fase 2, 4</span></div><div class="persona-badges"><span class="persona-badge arkitekt">🏗️ Arkitekt</span><span class="persona-badge driftsleder">⚙️ Driftsleder</span></div><p>Det vurderes, at netværksarkitekturen er rygraden i den fælles platform og skal designes til multi-tenancy, mikrosegmentering og automatisering fra første dag.</p><ul><li><p>Spine-leaf netværkstopologi (eller tilsvarende ikke-blokerende arkitektur) implementeres for at sikre forudsigelig, lav latency og høj båndbredde mellem alle noder i HCI-platformen.</p></li><li><p>Dedikerede netværk for storage-replikering, vMotion/live migration, management og tenant-trafik separeres fysisk eller logisk for at eliminere trafikkonkurrence.</p></li><li><p>Redundante forbindelser mellem sites (minimum to uafhængige ruter) dimensioneres til at håndtere fuld replikeringstrafik plus tenant-trafik ved site-failover.</p></li><li><p>QoS-policies implementeres på alle inter-site forbindelser for at prioritere replikering og kritisk tenant-trafik.</p></li><li><p>En skalerbar IP-adresseplan designes med forudallokerede subnets pr. tenant, miljøtype og funktion, understøttet af centraliseret IPAM.</p></li></ul>',5)])])}const m=r(i,[["render",n]]);export{g as __pageData,m as default};
